const ORGANIZER_EMAIL = 'YOUR_ORGANIZER_EMAIL';
const INTERNAL_DOMAIN = 'YOUR_INTERNAL_DOMAIN.com';
const SKIP_KEYWORDS = ['focus', 'block', 'lunch', 'ooo', 'hold', 'reminder', 'break'];

const results = [];

for (const item of $input.all()) {
  const event = item.json;

  // skip all-day events
  if (!event.start?.dateTime) continue;

  // skip by title keywords
  const title = (event.summary ?? '').toLowerCase();
  if (SKIP_KEYWORDS.some(k => title.includes(k))) continue;

  // remove organizer
  const others = (event.attendees ?? []).filter(a => a.email !== ORGANIZER_EMAIL);

  // skip solo blocks
  if (others.length === 0) continue;

  // classify by domain
  const external = others.filter(a => !a.email.endsWith(INTERNAL_DOMAIN));
  const internal = others.filter(a => a.email.endsWith(INTERNAL_DOMAIN));

  // meeting type
  let meetingType;
  if (external.length === 0) {
    meetingType = 'internal';
  } else if (external.length === 1) {
    meetingType = 'external_1to1';
  } else {
    meetingType = 'group';
  }

  results.push({
    json: {
      title: event.summary ?? 'Untitled Meeting',
      startTime: event.start.dateTime,
      endTime: event.end.dateTime,
      isRecurring: !!event.recurringEventId,
      meetingType,
      noMeetings: false,
      allAttendees: others,
      externalAttendees: external,
      internalAttendees: internal,
      primaryAttendee: external[0] ?? null,
    }
  });
}

if (results.length === 0) {
  return [{ json: { noMeetings: true } }];
}

return results;

