const formatMeeting = (meeting, type) => {
  const attendees = Array.isArray(meeting.attendees) ? meeting.attendees : [];

  const attendeeLines = attendees.map(a => {
    if (!a) return '';
    const lines = [];

    if (a.name) lines.push('Name: ' + a.name);
    if (a.jobTitle && a.company) lines.push('Role: ' + a.jobTitle + ' at ' + a.company);
    if (a.lifecycleStage) lines.push('CRM stage: ' + a.lifecycleStage);

    if (a.deal && a.deal.dealName) {
      let dealLine = 'Deal: ' + a.deal.dealName + ' — ' + safe(a.deal.dealStage);
      if (a.deal.amount) dealLine += ' — ' + a.deal.amount;
      lines.push(dealLine);
    }

    if (a.lastMeeting && a.lastMeeting.date) {
      lines.push('Last meeting (' + a.lastMeeting.date + '): ' + safe(a.lastMeeting.summary));
      if (Array.isArray(a.lastMeeting.actionItems) && a.lastMeeting.actionItems.length) {
        lines.push('Outstanding actions: ' + a.lastMeeting.actionItems.join(' | '));
      }
    }

    if (Array.isArray(a.emailThreads) && a.emailThreads.length) {
      const emails = a.emailThreads.map(e => safe(e.subject) + ' (' + safe(e.date) + '): ' + safe(e.snippet));
      lines.push('Recent emails: ' + emails.join(' | '));
    }

    if (Array.isArray(a.openTasks) && a.openTasks.length) {
      const tasks = a.openTasks.map(t => {
        let taskLine = safe(t.taskName) + ' — ' + safe(t.status);
        if (t.dueDate) taskLine += ' — due ' + t.dueDate;
        return taskLine;
      });
      lines.push('Open tasks: ' + tasks.join(' | '));
    }

    if (a.linkedin) {
      if (a.linkedin.headline) lines.push('LinkedIn: ' + a.linkedin.headline);
      if (Array.isArray(a.linkedin.recentPosts) && a.linkedin.recentPosts.length) {
        lines.push('Recent posts: ' + a.linkedin.recentPosts.join(' | '));
      }
    }

    return lines.join('\n');
  }).filter(Boolean).join('\n\n');

  const header = '[' + type.toUpperCase() + ' — ' + safe(meeting.meetingTitle) + ' at ' + safe(meeting.meetingTime) + (meeting.isRecurring ? ' — RECURRING' : '') + ']';
  return header + '\n' + attendeeLines;
};

const sections = [];

(Array.isArray(data.internalMeetings) ? data.internalMeetings : []).forEach(m => {
