          hubspotId: c.id,
          email: c.properties.email,
          firstName: c.properties.firstname ?? '',
          lastName: c.properties.lastname ?? '',
          fullName: `${c.properties.firstname ?? ''} ${c.properties.lastname ?? ''}`.trim(),
          jobTitle: c.properties.jobtitle ?? 'Unknown role',
          company: c.properties.company ?? 'Unknown company',
          lifecycleStage: c.properties.lifecyclestage ?? null,
