const DEAL_STAGES = {
  'decisionmakerboughtin': 'New Lead',
  'appointmentscheduled': 'Discovery Call Booked',
  'qualifiedtobuy': 'Proposal Sent',
  'presentationscheduled': 'Negotiation',
  'contractsent': 'Won',
  'closedwon': 'Closed Won',
  'closedlost': 'Closed Lost',
  'stage_0': 'Lost'
};

const allInputs = $input.all();

// Separate by shape — contacts have hubspotContact, deals have results array
const contactItems = allInputs.filter(i => i.json.hubspotContact !== undefined);
const dealItems = allInputs.filter(i => i.json.results !== undefined);

// Flatten and deduplicate deals
const seen = new Set();
const deals = [];
for (const item of dealItems) {
  for (const d of (item.json.results ?? [])) {
    if (seen.has(d.id) || !d.properties?.dealname) continue;
    seen.add(d.id);
    deals.push({
      dealName: d.properties.dealname,
      dealNameLower: d.properties.dealname.toLowerCase(),
      dealStage: DEAL_STAGES[d.properties.dealstage] ?? d.properties.dealstage,
      amount: d.properties.amount ? `$${d.properties.amount}` : null,
      closeDate: d.properties.closedate
        ? new Date(d.properties.closedate).toLocaleDateString('en-GB')
        : null,
      contactIds: (d.associations?.contacts?.results ?? []).map(r => r.id)
    });
  }
}

return contactItems.map(item => {
  const contact = item.json.hubspotContact;
  const id = contact?.hubspotId;
  const first = (contact?.firstName ?? '').toLowerCase();
  const last = (contact?.lastName ?? '').toLowerCase();

  const deal = deals.find(d => id && d.contactIds.includes(id))
    ?? deals.find(d => d.dealNameLower.includes(first) || d.dealNameLower.includes(last))
    ?? null;

  return {
    json: {
      meetingTitle: item.json.meetingTitle,
      meetingTime: item.json.meetingTime,
      meetingType: item.json.meetingType,
      isRecurring: item.json.isRecurring,
      isGroup: item.json.isGroup ?? false,
      allExternalAttendees: item.json.allExternalAttendees ?? [],
      primaryAttendee: item.json.primaryAttendee,
      hubspotContact: contact,
      hubspotDeal: deal ? {
        dealName: deal.dealName,
        dealStage: deal.dealStage,
        amount: deal.amount,
        closeDate: deal.closeDate
      } : { note: 'No active deal found for this contact' }
    }
