const meetingItems = $('combine').all();
const clickupTasks = $input.all();

return meetingItems.map(meetingItem => {
  const meeting = meetingItem.json;
  const primaryEmail = meeting.primaryAttendee?.email?.toLowerCase() ?? '';

  // Get first name from email for tight keyword match
  const namePart = primaryEmail.split('@')[0].toLowerCase();
  const nameParts = namePart.split('.').filter(p => p.length > 2);

  // Match by assignee email first
  const assigneeMatched = clickupTasks.filter(task =>
    (task.json.assignees ?? []).some(a =>
      (a.email ?? '').toLowerCase() === primaryEmail
    )
  );

  // Only keyword match if no assignee match found
  // AND keyword must match the attendee's own name — not meeting title
  const keywordMatched = assigneeMatched.length === 0
    ? clickupTasks.filter(task => {
        const taskName = (task.json.name ?? '').toLowerCase();
        return nameParts.some(p => taskName.includes(p));
      })
    : [];

  const matched = [...assigneeMatched, ...keywordMatched].map(t => ({
    taskName: t.json.name,
    status: t.json.status?.status ?? 'unknown',
    dueDate: t.json.due_date
      ? new Date(parseInt(t.json.due_date)).toLocaleDateString('en-GB')
      : null,
    assignees: (t.json.assignees ?? []).map(a => a.email).filter(Boolean)
  }));

  return {
    json: {
      _type: 'clickup',
      attendeeEmail: primaryEmail,
      meetingTitle: meeting.meetingTitle,
      meetingTime: meeting.meetingTime,
      meetingType: meeting.meetingType,
      isRecurring: meeting.isRecurring,
      isGroup: meeting.isGroup ?? false,
      allExternalAttendees: meeting.allExternalAttendees ?? [],
      primaryAttendee: meeting.primaryAttendee,
      openTasks: matched,
      noTasksFound: matched.length === 0,
      source: 'clickup_live'
    }
  };
});

