    recentPosts: [
      'Data sharing in healthcare — why interoperability is not just a technical problem but a trust problem that technology alone cannot solve.',
      'Fascinating discussion at the Lagos Health Summit on what real patient data portability looks like in practice.'
    ],
    profileUrl: 'https://linkedin.com/in/grace-eze-mock',
    note: 'Retrieved via Apify LinkedIn scraper — production implementation'
  }
};

return $input.all().map(item => {
  const input = item.json;
  const email = input.primaryAttendee?.email ?? input.attendeeEmail ?? '';

  const data = linkedinData[email] ?? {
    headline: null,
    recentPosts: [],
    profileUrl: null,
    note: 'LinkedIn data unavailable — no URL stored in HubSpot contact record'
  };

  return {
    json: {
      _type: 'linkedin',
      attendeeEmail: email,
      meetingTitle: input.meetingTitle,
      meetingTime: input.meetingTime,
      meetingType: input.meetingType,
      isRecurring: input.isRecurring,
      isGroup: input.isGroup ?? false,
      allExternalAttendees: input.allExternalAttendees ?? [],
      primaryAttendee: input.primaryAttendee,
      headline: data.headline,
      recentPosts: data.recentPosts,
      profileUrl: data.profileUrl,
      noLinkedinData: !data.headline,
      source: 'mock_apify'
    }
  };
});

const allInputs = $input.all();

const hubspotItems = allInputs.filter(i => i.json.hubspotContact !== undefined);
const fyxerItems = allInputs.filter(i => i.json._type === 'fyxer');
const gmailItems = allInputs.filter(i => i.json._type === 'gmail');
const clickupItems = allInputs.filter(i => i.json._type === 'clickup');
const linkedinItems = allInputs.filter(i => i.json._type === 'linkedin');
const internalItems = allInputs.filter(i =>
  i.json.meetingType === 'internal' &&
  i.json.hubspotContact === undefined &&
  i.json._type === undefined
);

// Format meeting time cleanly: "9:00 AM" or "12:00 PM"
const formatTime = (isoString) => {
  if (!isoString) return 'Time not set';
  const date = new Date(isoString);
  return date.toLocaleTimeString('en-GB', {
    hour: 'numeric',
    minute: '2-digit',
    hour12: true,
    timeZone: 'Africa/Lagos'
  }).toUpperCase();
};

const meetingMap = {};

hubspotItems.forEach(item => {
  const email = item.json.primaryAttendee?.email;
  if (!email) return;
  if (!meetingMap[email]) meetingMap[email] = {};
  Object.assign(meetingMap[email], {
    meetingTitle: item.json.meetingTitle,
    meetingTime: formatTime(item.json.meetingTime),
    meetingType: item.json.meetingType,
    isRecurring: item.json.isRecurring,
    isGroup: item.json.isGroup ?? false,
    allExternalAttendees: item.json.allExternalAttendees ?? [],
    primaryAttendee: item.json.primaryAttendee,
    hubspotContact: item.json.hubspotContact,
    hubspotDeal: item.json.hubspotDeal
  });
});

fyxerItems.forEach(item => {
  const email = item.json.attendeeEmail;
  if (!email || !meetingMap[email]) return;
  meetingMap[email].lastMeeting = item.json.summary
    ? { date: item.json.lastMeetingDate, summary: item.json.summary, actionItems: item.json.actionItems ?? [] }
    : null;
});

gmailItems.forEach(item => {
  const email = item.json.attendeeEmail;
  if (!email || !meetingMap[email]) return;
  meetingMap[email].emailThreads = (item.json.threads ?? []).length > 0 ? item.json.threads : null;
});

clickupItems.forEach(item => {
  const email = item.json.attendeeEmail;
  if (!email || !meetingMap[email]) return;
  meetingMap[email].openTasks = (item.json.openTasks ?? []).length > 0 ? item.json.openTasks : null;
});

linkedinItems.forEach(item => {
  const email = item.json.attendeeEmail;
  if (!email || !meetingMap[email]) return;
  meetingMap[email].linkedin = item.json.headline
    ? { headline: item.json.headline, recentPosts: item.json.recentPosts ?? [] }
    : null;
});

const meetingGroups = {};
Object.values(meetingMap).forEach(m => {
  const key = m.meetingTitle + m.meetingTime;
  if (!meetingGroups[key]) {
    meetingGroups[key] = {
      meetingTitle: m.meetingTitle,
      meetingTime: m.meetingTime,
      meetingType: m.meetingType,
      isRecurring: m.isRecurring,
      isGroup: m.isGroup,
      attendees: []
    };
  }
  meetingGroups[key].attendees.push({
    name: m.hubspotContact?.fullName ?? m.primaryAttendee?.email,
    email: m.primaryAttendee?.email,
    jobTitle: m.hubspotContact?.jobTitle ?? null,
    company: m.hubspotContact?.company ?? null,
    lifecycleStage: m.hubspotContact?.lifecycleStage ?? null,
    deal: m.hubspotDeal?.note ? null : m.hubspotDeal,
    lastMeeting: m.lastMeeting ?? null,
    emailThreads: m.emailThreads ?? null,
    openTasks: m.openTasks ?? null,
    linkedin: m.linkedin ?? null
  });
});

const internalMeetings = internalItems.map(i => ({
  meetingTitle: i.json.meetingTitle,
  meetingTime: formatTime(i.json.meetingTime),
  meetingType: 'internal',
  isRecurring: i.json.isRecurring,
  attendees: (i.json.attendees ?? []).map(a => ({
    name: a.name,
    email: a.email,
    openTasks: (a.openTasks ?? []).length > 0 ? a.openTasks : null,
    lastMeeting: a.lastMeeting?.summary && a.lastMeeting.summary !== 'No previous meeting summary found'
      ? a.lastMeeting
      : null
  }))
}));

// Sort all meetings by time
const externalMeetings = Object.values(meetingGroups).sort((a, b) =>
  a.meetingTime.localeCompare(b.meetingTime)
);

const allMeetingsSorted = [
  ...internalMeetings,
  ...externalMeetings
].sort((a, b) => a.meetingTime.localeCompare(b.meetingTime));

return [{
  json: {
    date: new Date().toLocaleDateString('en-GB', {
      weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
    }),
    totalMeetings: externalMeetings.length + internalMeetings.length,
    internalMeetings,
    externalMeetings,
    allMeetingsSorted
  }
}];

const input = $input.first().json;
