const section = (title, list) => {
  if (!list || list.length === 0) return '';

  const colors = {
    'Internal Meetings': '#4A90D9',
    'External Meetings': '#7B68EE',
    'Group Meetings': '#50C878'
  };
  const accent = colors[title] || '#888';

  const heading = `
    <table width="100%" cellpadding="0" cellspacing="0" style="margin:0 0 20px;">
      <tr>
        <td width="3" style="background:${accent};border-radius:2px;">&nbsp;</td>
        <td style="padding-left:10px;font-weight:700;font-size:12px;text-transform:uppercase;letter-spacing:1.2px;color:${accent};">${title}</td>
      </tr>
    </table>`;

  const items = list.map((meeting, i) => {
    const isLast = i === list.length - 1;
    return `
    <div style="margin-bottom:${isLast ? '8' : '22'}px;padding-bottom:${isLast ? '0' : '22'}px;border-bottom:${isLast ? 'none' : '1px solid #ebebeb'};">
      <p style="margin:0 0 7px;font-size:16px;font-weight:700;color:#111;">${meeting.time} <span style="color:#ccc;font-weight:400;">|</span> ${meeting.title}</p>
      <p style="margin:0;color:#444;line-height:1.9;font-size:14.5px;">
        <span style="color:#999;font-style:italic;">${meeting.points[0]}</span>
        ${meeting.points.slice(1).join(' ')}
      </p>
    </div>`;
  }).join('');

  return `
  <div style="margin-bottom:20px;background:#F7F8FA;border:1px solid #e2e4e8;border-radius:8px;padding:22px 26px;">
    ${heading}
    ${items}
  </div>`;
};

const html = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"></head>
<body style="font-family:'Helvetica Neue',Arial,sans-serif;font-size:15px;color:#1a1a1a;line-height:1.85;max-width:680px;margin:0 auto;padding:24px;background:#EDEEF0;">

  <div style="background:#F7F8FA;border:1px solid #e2e4e8;border-radius:8px;padding:22px 26px;margin-bottom:16px;">
    <p style="margin:0 0 4px;font-size:12px;color:#999;text-transform:uppercase;letter-spacing:0.8px;">Meeting Prep Brief</p>
    <p style="margin:0;font-size:24px;font-weight:700;color:#111;">${data.date}</p>
