  </div>

  <div style="background:#F7F8FA;border:1px solid #e2e4e8;border-radius:8px;padding:20px 26px;margin-bottom:20px;">
    <p style="margin:0;font-size:15px;color:#333;line-height:1.8;">Hi Landon, here is your meeting brief for the day. You have <strong>${data.totalMeetings} meetings</strong> scheduled. Kindly review the context and talking points below before your day starts.</p>
  </div>

  ${section('Internal Meetings', m.internal)}
  ${section('External Meetings', m.external)}
  ${section('Group Meetings', m.group)}

  <p style="margin-top:12px;font-size:12px;color:#bbb;text-align:center;">Prepared by SolSombra Meeting Prep Automation</p>

</body>
</html>`;

return [{ json: { html, date: data.date, totalMeetings: data.totalMeetings } }];

